const message = $input.first().json.message.text.toLowerCase();
const chatId = $input.first().json.message.chat.id;
const userId = $input.first().json.message.from.id;
const userName = $input.first().json.message.from.first_name;

let category = 'otros';
let priority = 'normal';

// Clasificación por palabras clave
if (message.includes('precio') || message.includes('comprar') || message.includes('producto') || message.includes('costo')) {
  category = 'ventas';
} else if (message.includes('problema') || message.includes('error') || message.includes('no funciona') || message.includes('ayuda')) {
  category = 'soporte';
} else if (message.includes('factura') || message.includes('pago') || message.includes('recibo') || message.includes('facturación')) {
  category = 'facturación';
}

// Detectar urgencia
const urgentWords = ['urgente', 'inmediato', 'ya', 'ahora mismo', 'enojado', 'queja'];
if (urgentWords.some(word => message.includes(word))) {
  priority = 'alta';
}

return [{
  json: {
    chatId,
    userId,
    userName,
    originalMessage: $input.first().json.message.text,
    category,
    priority,
    timestamp: new Date().toISOString()
  }
}];

const respuestasVentas = [
  "¡Hola {{userName}}! 👋 Gracias por tu interés en nuestros productos. Tenemos opciones desde $50 hasta $500. ¿Qué te gustaría conocer?",
  "¡Excelente pregunta! 🛍️ Tenemos envío gratis en compras mayores a $100. ¿Hay algún producto específico que te interese?",
  "¡Claro que sí! 😊 Nuestros productos tienen garantía de 1 año. ¿Te puedo ayudar con algo específico?"
];

const chatId = $input.first().json.chatId;
const userName = $input.first().json.userName || 'cliente';
const respuesta = respuestasVentas[Math.floor(Math.random() * respuestasVentas.length)].replace('{{userName}}', userName);

return [{
  json: {
    chatId,
    text: respuesta,
    category: 'ventas'
  }
}];

const respuestasSoporte = [
  "Entiendo que tienes un problema 🔧. ¿Podrías darme más detalles sobre qué no está funcionando?",
  "Lamento escuchar eso 😕. Voy a ayudarte a resolverlo. ¿Cuándo comenzó el problema?",
  "¡Gracias por reportarlo! 🛠️ Nuestro equipo de soporte está aquí para ayudarte. ¿Qué error estás viendo?"
];

const chatId = $input.first().json.chatId;
const respuesta = respuestasSoporte[Math.floor(Math.random() * respuestasSoporte.length)];

return [{
  json: {
    chatId,
    text: respuesta,
    category: 'soporte'
  }
}];

const respuestasFacturacion = [
  "📄 Tu factura se genera automáticamente después del pago. ¿Necesitas que reenviemos la tuya?",
  "💳 Los métodos de pago aceptados son: tarjeta, transferencia y PayPal. ¿Con cuál tienes duda?",
  "✅ Todos nuestros pagos son seguros y encriptados. ¿En qué te puedo ayudar con tu factura?"
];

const chatId = $input.first().json.chatId;
const respuesta = respuestasFacturacion[Math.floor(Math.random() * respuestasFacturacion.length)];

return [{
  json: {
    chatId,
    text: respuesta,
    category: 'facturación'
  }
}];

const chatId = $input.first().json.chatId;

return [{
  json: {
    chatId,
    text: "Gracias por tu mensaje. 🙏 Un agente humano te responderá en breve. ¿Hay algo más en lo que pueda ayudarte mientras tanto?",
    category: 'otros',
    escalateToHuman: true
  }
}];
